import{_ as e,C as t,o as l,c as n,a2 as a,E as h,w as p,a as o}from"./chunks/framework.BRk9mohw.js";const y=JSON.parse('{"title":"认证","description":"","frontmatter":{},"headers":[],"relativePath":"tools/gateway/authentication.md","filePath":"tools/gateway/authentication.md"}'),d={name:"tools/gateway/authentication.md"};function k(c,s,r,F,g,u){const i=t("Warning");return l(),n("div",null,[s[1]||(s[1]=a(`<h1 id="认证" tabindex="-1">认证 <a class="header-anchor" href="#认证" aria-label="Permalink to &quot;认证&quot;">​</a></h1><p>OpenClaw 支持模型提供商的 OAuth 和 API 密钥。对于永远在线的网关主机，API 密钥通常是最可预测的选项。当它们与你的提供商账户模型匹配时，也支持订阅/OAuth 流程。</p><p>请参阅 <a href="/concepts/oauth.html">/concepts/oauth</a> 了解完整的 OAuth 流程和存储布局。 对于基于 SecretRef 的认证（<code>env</code>/<code>file</code>/<code>exec</code> 提供商），请参阅 <a href="/gateway/secrets.html">Secrets Management</a>。 有关 <code>models status --probe</code> 使用的凭据资格/原因代码规则，请参阅 <a href="/auth-credential-semantics.html">Auth Credential Semantics</a>。</p><h2 id="推荐设置-api-密钥-任何提供商" tabindex="-1">推荐设置（API 密钥，任何提供商） <a class="header-anchor" href="#推荐设置-api-密钥-任何提供商" aria-label="Permalink to &quot;推荐设置（API 密钥，任何提供商）&quot;">​</a></h2><p>如果你正在运行长期网关，请从你选择的提供商开始使用 API 密钥。 对于 Anthropic，具体来说，API 密钥认证是安全路径，比订阅 setup-token 认证更推荐。</p><ol><li>在你的提供商控制台中创建 API 密钥。</li><li>将其放在<strong>网关主机</strong>上（运行 <code>openclaw gateway</code> 的机器）。</li></ol><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">PROVIDER</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">_API_KEY</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;...&quot;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> models</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> status</span></span></code></pre></div><ol start="3"><li>如果网关在 systemd/launchd 下运行，优先将密钥放在 <code>~/.openclaw/.env</code> 中，以便守护进程可以读取它：</li></ol><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cat</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &gt;&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.openclaw/.env</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;EOF&#39;</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&lt;PROVIDER&gt;_API_KEY=...</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">EOF</span></span></code></pre></div><p>然后重启守护进程（或重启你的网关进程）并重新检查：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> models</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> status</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> doctor</span></span></code></pre></div><p>如果你不想自己管理环境变量，onboarding 可以为守护进程存储 API 密钥：<code>openclaw onboard</code>。</p><p>请参阅 <a href="/help.html">Help</a> 了解环境继承详情（<code>env.shellEnv</code>、<code>~/.openclaw/.env</code>、systemd/launchd）。</p><h2 id="anthropic-setup-token-订阅认证" tabindex="-1">Anthropic：setup-token（订阅认证） <a class="header-anchor" href="#anthropic-setup-token-订阅认证" aria-label="Permalink to &quot;Anthropic：setup-token（订阅认证）&quot;">​</a></h2><p>如果你使用 Claude 订阅，支持 setup-token 流程。在<strong>网关主机</strong>上运行：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">claude</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> setup-token</span></span></code></pre></div><p>然后粘贴到 OpenClaw：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> models</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> auth</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> setup-token</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --provider</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> anthropic</span></span></code></pre></div><p>如果令牌是在另一台机器上创建的，手动粘贴：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> models</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> auth</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> paste-token</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --provider</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> anthropic</span></span></code></pre></div><p>如果你看到类似这样的 Anthropic 错误：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>This credential is only authorized for use with Claude Code and cannot be used for other API requests.</span></span></code></pre></div><p>…请改用 Anthropic API 密钥。</p>`,23)),h(i,null,{default:p(()=>[...s[0]||(s[0]=[o(" Anthropic setup-token 支持仅为技术兼容性。Anthropic 过去曾在 Claude Code 之外阻止了一些订阅使用。仅在你认为政策风险可接受的情况下使用它，并自行验证 Anthropic 的当前条款。 ",-1)])]),_:1}),s[2]||(s[2]=a(`<p>手动令牌输入（任何提供商；写入 <code>auth-profiles.json</code> + 更新配置）：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> models</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> auth</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> paste-token</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --provider</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> anthropic</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> models</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> auth</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> paste-token</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --provider</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> openrouter</span></span></code></pre></div><p>还支持用于静态凭据的 auth profile 引用：</p><ul><li><code>api_key</code> 凭据可以使用 <code>keyRef: { source, provider, id }</code></li><li><code>token</code> 凭据可以使用 <code>tokenRef: { source, provider, id }</code></li></ul><p>自动化友好检查（过期/缺失时退出 <code>1</code>，即将过期时退出 <code>2</code>）：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> models</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> status</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --check</span></span></code></pre></div><p>可选运维脚本（systemd/Termux）记录在此处： <a href="/automation/auth-monitoring.html">/automation/auth-monitoring</a></p><blockquote><p><code>claude setup-token</code> 需要交互式 TTY。</p></blockquote><h2 id="检查模型认证状态" tabindex="-1">检查模型认证状态 <a class="header-anchor" href="#检查模型认证状态" aria-label="Permalink to &quot;检查模型认证状态&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> models</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> status</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> doctor</span></span></code></pre></div><h2 id="api-密钥轮换行为-网关" tabindex="-1">API 密钥轮换行为（网关） <a class="header-anchor" href="#api-密钥轮换行为-网关" aria-label="Permalink to &quot;API 密钥轮换行为（网关）&quot;">​</a></h2><p>某些提供商支持在 API 调用遇到提供商速率限制时使用替代密钥重试请求。</p><ul><li>优先级顺序： <ul><li><code>OPENCLAW_LIVE_&lt;PROVIDER&gt;_KEY</code>（单一覆盖）</li><li><code>&lt;PROVIDER&gt;_API_KEYS</code></li><li><code>&lt;PROVIDER&gt;_API_KEY</code></li><li><code>&lt;PROVIDER&gt;_API_KEY_*</code></li></ul></li><li>Google 提供商还包括 <code>GOOGLE_API_KEY</code> 作为额外回退。</li><li>同一密钥列表在使用前先去重。</li><li>OpenClaw 仅对速率限制错误重试下一个密钥（例如 <code>429</code>、<code>rate_limit</code>、<code>quota</code>、<code>resource exhausted</code>）。</li><li>非速率限制错误不会使用替代密钥重试。</li><li>如果所有密钥都失败，则返回最后尝试的错误。</li></ul><h2 id="控制使用哪个凭据" tabindex="-1">控制使用哪个凭据 <a class="header-anchor" href="#控制使用哪个凭据" aria-label="Permalink to &quot;控制使用哪个凭据&quot;">​</a></h2><h3 id="每会话-聊天命令" tabindex="-1">每会话（聊天命令） <a class="header-anchor" href="#每会话-聊天命令" aria-label="Permalink to &quot;每会话（聊天命令）&quot;">​</a></h3><p>使用 <code>/model &lt;alias-or-id&gt;@&lt;profileId&gt;</code> 为当前会话固定特定提供商凭据（示例 profile ids：<code>anthropic:default</code>、<code>anthropic:work</code>）。</p><p>使用 <code>/model</code>（或 <code>/model list</code>）获取紧凑选择器；使用 <code>/model status</code> 获取完整视图（候选 + 下一个 auth profile，以及配置了提供商端点详情时）。</p><h3 id="每代理-cli-覆盖" tabindex="-1">每代理（CLI 覆盖） <a class="header-anchor" href="#每代理-cli-覆盖" aria-label="Permalink to &quot;每代理（CLI 覆盖）&quot;">​</a></h3><p>为代理设置显式 auth profile 顺序覆盖（存储在该代理的 <code>auth-profiles.json</code> 中）：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> models</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> auth</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> order</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> get</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --provider</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> anthropic</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> models</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> auth</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> order</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> set</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --provider</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> anthropic</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> anthropic:default</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> models</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> auth</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> order</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clear</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --provider</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> anthropic</span></span></code></pre></div><p>使用 <code>--agent &lt;id&gt;</code> 定位特定代理；省略它以使用配置的默认代理。</p><h2 id="故障排除" tabindex="-1">故障排除 <a class="header-anchor" href="#故障排除" aria-label="Permalink to &quot;故障排除&quot;">​</a></h2><h3 id="no-credentials-found" tabindex="-1">&quot;No credentials found&quot; <a class="header-anchor" href="#no-credentials-found" aria-label="Permalink to &quot;&quot;No credentials found&quot;&quot;">​</a></h3><p>如果缺少 Anthropic token profile，请在<strong>网关主机</strong>上运行 <code>claude setup-token</code>，然后重新检查：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> models</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> status</span></span></code></pre></div><h3 id="token-即将过期-已过期" tabindex="-1">Token 即将过期/已过期 <a class="header-anchor" href="#token-即将过期-已过期" aria-label="Permalink to &quot;Token 即将过期/已过期&quot;">​</a></h3><p>运行 <code>openclaw models status</code> 确认哪个 profile 即将过期。如果 profile 缺失，请重新运行 <code>claude setup-token</code> 并再次粘贴令牌。</p><h2 id="要求" tabindex="-1">要求 <a class="header-anchor" href="#要求" aria-label="Permalink to &quot;要求&quot;">​</a></h2><ul><li>Anthropic 订阅账户（用于 <code>claude setup-token</code>）</li><li>Claude Code CLI 已安装（<code>claude</code> 命令可用）</li></ul>`,29))])}const b=e(d,[["render",k]]);export{y as __pageData,b as default};
